python3 - <<"PY"
import socket
import ssl
import sys

ip = "{TARGET_IP}"

try:
    sock = socket.create_connection((ip, 443), timeout=8)
except Exception as e:
    print(f"connect_failed: {e}", file=sys.stderr)
    raise SystemExit(1)

try:
    ctx = ssl._create_unverified_context()
    try:
        ssock = ctx.wrap_socket(sock, server_hostname="one.one.one.one")
        try:
            ssock.sendall(
                b"GET / HTTP/1.1\r\n"
                b"Host: one.one.one.one\r\n"
                b"Connection: close\r\n"
                b"\r\n"
            )
            ssock.recv(64)
        except Exception:
            pass
        finally:
            try:
                ssock.close()
            except Exception:
                pass
    except Exception:
        # Even a failed handshake still indicates egress; try a plain write.
        try:
            sock.sendall(b"PING\r\n")
            sock.recv(16)
        except Exception:
            pass
finally:
    try:
        sock.close()
    except Exception:
        pass

print("ok")
PY
